func (s *InMemoryStore) GetTransactionsForAccount(accountID string, startDate, endDate string, pageSize int, pageToken string) ([]*pb.Transaction, string, int) {
	txnIDs := s.accountTxns[accountID]
	var results []*pb.Transaction

	startIdx := 0
	if pageToken != "" {
		for i, id := range txnIDs {
			if id == pageToken {
				startIdx = i + 1
				break
			}
		}
	}

	for i := startIdx; i < len(txnIDs); i++ {
		txn := s.transactions[txnIDs[i]]

		if startDate != "" {
			t, err := time.Parse(time.RFC3339, txn.CreatedAt)
			if err == nil {
				sd, err := time.Parse(time.RFC3339, startDate)
				if err == nil && t.Before(sd) {
					continue
				}
			}
		}
		if endDate != "" {
			t, err := time.Parse(time.RFC3339, txn.CreatedAt)
			if err == nil {
				ed, err := time.Parse(time.RFC3339, endDate)
				if err == nil && t.After(ed) {
					continue
				}
			}
		}

		results = append(results, txn)
		if pageSize > 0 && len(results) >= pageSize {
			break
		}
	}

	nextToken := ""
	if len(results) > 0 && pageSize > 0 && startIdx+len(results) < len(txnIDs) {
		nextToken = results[len(results)-1].TransactionId
	}

	return results, nextToken, len(txnIDs)
}

